<template>
  <section class="portal-module invoice-module">
    <div class="portal-module__head"><div><span class="portal-module__eyebrow">Notas fiscais</span></div><q-btn v-if="admin" unelevated no-caps class="portal-module__primary" icon="mdi-plus" label="Nova nota fiscal" @click="openCreate" /></div>
    <div v-if="admin" class="invoice-module__filters"><q-input v-model="search" outlined dense clearable label="Buscar titulo ou numero" @keyup.enter="load"><template #prepend><q-icon name="mdi-magnify" /></template></q-input><q-btn flat round icon="mdi-refresh" aria-label="Atualizar notas" :loading="loading" @click="load" /></div>
    <q-table flat bordered wrap-cells row-key="_id" class="portal-module__table" :rows="invoices" :columns="columns" :loading="loading" no-data-label="Nenhuma nota fiscal encontrada"><template #body-cell-targetUser="props"><q-td :props="props">{{ props.row.targetUser?.name || '-' }}</q-td></template><template #body-cell-project="props"><q-td :props="props">{{ props.row.project?.title || '-' }}</q-td></template><template #body-cell-description="props"><q-td :props="props"><span class="invoice-module__description">{{ preview(props.row.description) }}</span></q-td></template><template #body-cell-status="props"><q-td :props="props"><span class="portal-module__tag">{{ statusLabel(props.row.status) }}</span></q-td></template><template #body-cell-amount="props"><q-td :props="props">{{ money(props.row.amount, props.row.currency) }}</q-td></template><template #body-cell-date="props"><q-td :props="props">{{ formatDate(props.row.issueDate) }}</q-td></template><template #body-cell-attachment="props"><q-td :props="props"><a v-if="props.row.attachment" :href="props.row.attachment.url" target="_blank" rel="noopener noreferrer" class="portal-module__link"><q-icon name="mdi-paperclip" /> Abrir</a><span v-else>-</span></q-td></template><template #body-cell-actions="props"><q-td :props="props"><q-btn flat round dense icon="mdi-eye-outline" aria-label="Ver detalhes" @click="openDetails(props.row)" /><q-btn v-if="admin" flat round dense icon="mdi-pencil" aria-label="Editar nota fiscal" @click="openEdit(props.row)" /><q-btn v-if="admin" flat round dense color="negative" icon="mdi-delete-outline" aria-label="Excluir nota fiscal" @click="remove(props.row)" /></q-td></template></q-table>
    <q-dialog v-model="dialog"><q-card class="portal-module__dialog invoice-module__dialog"><q-card-section class="portal-module__dialog-head"><div><span class="portal-module__eyebrow">Documento fiscal</span><h3>{{ form._id ? 'Editar nota fiscal' : 'Cadastrar nota fiscal' }}</h3></div><q-btn flat round dense icon="mdi-close" aria-label="Fechar" @click="dialog = false" /></q-card-section><q-card-section><q-form @submit.prevent="save"><q-select v-model="form.targetUserId" outlined label="Cliente" :options="customerOptions" emit-value map-options :rules="[requiredRule]" /><q-select v-model="form.projectId" outlined clearable label="Projeto" :options="projectOptions" emit-value map-options class="q-mt-sm" /><q-input v-model="form.title" outlined label="Titulo" class="q-mt-sm" :rules="[requiredRule]" /><q-input v-model="form.number" outlined label="Numero da nota" class="q-mt-sm" /><div class="invoice-module__grid"><q-select v-model="form.status" outlined label="Status" :options="statusOptions" emit-value map-options /><q-select v-model="form.currency" outlined label="Moeda" :options="currencyOptions" emit-value map-options /></div><div class="invoice-module__grid"><q-input v-model.number="form.amount" outlined type="number" min="0" step="0.01" label="Valor" /><q-input v-model="form.issueDate" outlined type="date" label="Data de emissao" /></div><q-input v-model="form.dueDate" outlined type="date" label="Vencimento" class="q-mt-sm" /><q-input v-model="form.description" outlined type="textarea" autogrow label="Descricao" class="q-mt-sm" /><q-file v-model="form.file" outlined label="Anexo da nota" accept="image/*,.pdf,.doc,.docx,.xls,.xlsx,.csv" class="q-mt-sm"><template #prepend><q-icon name="mdi-paperclip" /></template></q-file><q-toggle v-if="form._id && form.attachment" v-model="form.removeAttachment" label="Remover anexo atual" color="negative" class="q-mt-sm" /><q-btn unelevated no-caps class="portal-module__primary full-width q-mt-md" type="submit" label="Salvar nota fiscal" :loading="saving" /></q-form></q-card-section></q-card></q-dialog>
    <q-dialog v-model="detailDialog"><q-card class="portal-module__dialog"><q-card-section class="portal-module__dialog-head"><div><span class="portal-module__eyebrow">Detalhes</span><h3>{{ selectedDetail.title || 'Nota fiscal' }}</h3></div><q-btn flat round dense icon="mdi-close" aria-label="Fechar" @click="detailDialog = false" /></q-card-section><q-card-section class="invoice-module__detail"><p>{{ selectedDetail.description || 'Sem descricao cadastrada.' }}</p><div><span>Cliente</span><strong>{{ selectedDetail.targetUser?.name || '-' }}</strong></div><div><span>Projeto</span><strong>{{ selectedDetail.project?.title || '-' }}</strong></div><div><span>Valor</span><strong>{{ money(selectedDetail.amount, selectedDetail.currency) }}</strong></div></q-card-section></q-card></q-dialog>
  </section>
</template>

<script setup>
import { computed, onMounted, ref } from 'vue'
import { useQuasar } from 'quasar'
import { api } from 'boot/axios'
const props = defineProps({ admin: { type: Boolean, default: false } }); const $q = useQuasar(); const token = localStorage.getItem(props.admin ? 'aito_admin_token' : 'aito_user_token'); const headers = { Authorization: `Bearer ${token}` }; const invoices = ref([]); const customers = ref([]); const projects = ref([]); const loading = ref(false); const saving = ref(false); const dialog = ref(false); const detailDialog = ref(false); const search = ref(''); const form = ref(emptyForm()); const selectedDetail = ref({})
const statusOptions = [{ label: 'Rascunho', value: 'draft' }, { label: 'Emitida', value: 'issued' }, { label: 'Paga', value: 'paid' }, { label: 'Vencida', value: 'overdue' }, { label: 'Cancelada', value: 'cancelled' }]; const currencyOptions = [{ label: 'Real (BRL)', value: 'BRL' }, { label: 'Dolar (USD)', value: 'USD' }]; const customerOptions = computed(() => customers.value.map((item) => ({ label: `${item.name} - ${item.email}`, value: item._id }))); const projectOptions = computed(() => projects.value.filter((item) => !form.value.targetUserId || item.client?.id === form.value.targetUserId).map((item) => ({ label: item.title, value: item._id }))); const columns = computed(() => props.admin ? [{ name: 'title', label: 'Titulo', field: 'title', align: 'left', sortable: true }, { name: 'targetUser', label: 'Cliente', field: row => row.targetUser?.name || '-', align: 'left' }, { name: 'project', label: 'Projeto', field: row => row.project?.title || '-', align: 'left' }, { name: 'description', label: 'Descricao', field: 'description', align: 'left' }, { name: 'status', label: 'Status', field: 'status', align: 'left' }, { name: 'amount', label: 'Valor', field: 'amount', align: 'right' }, { name: 'date', label: 'Emissao', field: 'issueDate', align: 'left' }, { name: 'attachment', label: 'Anexo', field: 'attachment', align: 'left' }, { name: 'actions', label: '', align: 'right' }] : [{ name: 'title', label: 'Titulo', field: 'title', align: 'left', sortable: true }, { name: 'project', label: 'Projeto', field: row => row.project?.title || '-', align: 'left' }, { name: 'description', label: 'Descricao', field: 'description', align: 'left' }, { name: 'status', label: 'Status', field: 'status', align: 'left' }, { name: 'amount', label: 'Valor', field: 'amount', align: 'right' }, { name: 'date', label: 'Emissao', field: 'issueDate', align: 'left' }, { name: 'attachment', label: 'Anexo', field: 'attachment', align: 'left' }, { name: 'actions', label: '', align: 'right' }])
function emptyForm () { return { _id: '', targetUserId: '', projectId: '', title: '', number: '', description: '', status: 'draft', issueDate: new Date().toISOString().slice(0, 10), dueDate: '', amount: 0, currency: 'BRL', file: null, attachment: null, removeAttachment: false } }
function requiredRule (value) { return Boolean(String(value || '').trim()) || 'Preencha este campo.' }; function preview (value) { const text = String(value || '').trim(); return text.length > 48 ? `${text.slice(0, 48)}...` : text || '-' }; function money (value, currency = 'BRL') { return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: currency || 'BRL' }).format(Number(value || 0)) }; function formatDate (value) { return value ? new Date(value).toLocaleDateString('pt-BR') : '-' }; function statusLabel (value) { return statusOptions.find((item) => item.value === value)?.label || value || '-' }; function selectedFile (value) { return value?.item ? value.item(0) : Array.isArray(value) ? value[0] : value }
function openCreate () { form.value = emptyForm(); dialog.value = true }; function openEdit (item) { form.value = { ...emptyForm(), ...item, targetUserId: item.targetUser?._id || item.targetUser?.id || '', projectId: item.project?._id || item.project?.id || '', issueDate: item.issueDate ? String(item.issueDate).slice(0, 10) : '', dueDate: item.dueDate ? String(item.dueDate).slice(0, 10) : '', file: null, removeAttachment: false }; dialog.value = true }; function openDetails (item) { selectedDetail.value = item; detailDialog.value = true }
async function load () { loading.value = true; try { const response = await api.get(props.admin ? '/admin/invoices' : '/invoices', { headers, params: props.admin ? { q: search.value } : undefined }); invoices.value = response.data.data || []; if (props.admin) { const [clientResponse, projectResponse] = await Promise.all([api.get('/admin/customers', { headers }), api.get('/admin/projects', { headers })]); customers.value = clientResponse.data.data || []; projects.value = projectResponse.data.data || [] } } catch (error) { notifyError(error) } finally { loading.value = false } }
async function save () { saving.value = true; try { const body = new FormData(); ['targetUserId', 'projectId', 'title', 'number', 'description', 'status', 'issueDate', 'dueDate', 'amount', 'currency'].forEach((key) => body.append(key, form.value[key] ?? '')); if (form.value.removeAttachment) body.append('removeAttachment', 'true'); const file = selectedFile(form.value.file); if (file) body.append('attachment', file); const endpoint = form.value._id ? `/admin/invoices/${form.value._id}` : '/admin/invoices'; const response = form.value._id ? await api.put(endpoint, body, { headers }) : await api.post(endpoint, body, { headers }); if (form.value._id) invoices.value = invoices.value.map((item) => item._id === form.value._id ? response.data.data : item); else invoices.value.unshift(response.data.data); dialog.value = false; $q.notify({ type: 'positive', message: 'Nota fiscal salva.' }) } catch (error) { notifyError(error) } finally { saving.value = false } }
function remove (item) { $q.dialog({ title: 'Excluir nota fiscal', message: `Remover ${item.title}?`, cancel: true, persistent: true }).onOk(async () => { try { await api.delete(`/admin/invoices/${item._id}`, { headers }); invoices.value = invoices.value.filter((invoice) => invoice._id !== item._id); $q.notify({ type: 'positive', message: 'Nota fiscal removida.' }) } catch (error) { notifyError(error) } }) }; function notifyError (error) { $q.notify({ type: 'negative', message: error.response?.data?.message || 'Nao foi possivel concluir a nota fiscal.' }) }; onMounted(load)
</script>

<style scoped>
.portal-module { display: grid; gap: 1rem; color: #effffb; }.portal-module__head { display: flex; align-items: flex-end; justify-content: space-between; gap: 1rem; }.portal-module__eyebrow { color: #8fffee; font-size: .66rem; font-weight: 900; letter-spacing: .14em; text-transform: uppercase; }.portal-module h2 { margin: .45rem 0 0; color: #effffb; font-size: clamp(1.5rem, 3vw, 2.5rem); }.portal-module__head p { margin: .45rem 0 0; color: rgba(229,255,250,.62); font-size: .78rem; }.portal-module__primary { color: #03110f; background: linear-gradient(135deg, #8fffee, #13bc9d); font-weight: 800; }.portal-module__table { color: #effffb; border-color: rgba(19,188,157,.2); background: rgba(3,16,18,.6); }.portal-module__table :deep(th) { color: #8fffee; font-size: .68rem; }.portal-module__table :deep(td) { color: rgba(239,255,251,.78); font-size: .72rem; }.portal-module__tag { padding: .25rem .45rem; border: 1px solid rgba(19,188,157,.28); border-radius: 999px; color: #8fffee; font-size: .62rem; }.portal-module__link { color: #8fffee; text-decoration: none; }.invoice-module__filters { display: flex; gap: .6rem; }.invoice-module__filters :deep(.q-field) { flex: 1; max-width: 420px; }.invoice-module__filters :deep(.q-field__control), .invoice-module__dialog :deep(.q-field__control) { color: #effffb; background: rgba(7,40,40,.74); }.invoice-module__filters :deep(.q-field__native), .invoice-module__filters :deep(.q-field__label), .invoice-module__dialog :deep(.q-field__native), .invoice-module__dialog :deep(.q-field__label) { color: rgba(239,255,251,.8); }.invoice-module__description { display: inline-block; max-width: 18rem; }.portal-module__dialog { width: min(94vw, 650px); color: #effffb; background: #061819; border: 1px solid rgba(19,188,157,.3); }.portal-module__dialog-head { display: flex; align-items: flex-start; justify-content: space-between; gap: .8rem; }.portal-module__dialog h3 { margin: .4rem 0 0; font-size: 1.15rem; }.invoice-module__grid { display: grid; grid-template-columns: 1fr 1fr; gap: .6rem; margin-top: .6rem; }.invoice-module__detail { display: grid; gap: .8rem; color: rgba(239,255,251,.82); }.invoice-module__detail p { margin: 0; white-space: pre-wrap; line-height: 1.6; }.invoice-module__detail div { display: flex; justify-content: space-between; gap: 1rem; padding-top: .7rem; border-top: 1px solid rgba(143,255,238,.1); }.invoice-module__detail span { color: rgba(229,255,250,.58); }@media (max-width: 700px) { .portal-module__head { align-items: flex-start; flex-direction: column; }.portal-module__primary { width: 100%; }.invoice-module__grid { grid-template-columns: 1fr; }.portal-module__table { max-width: calc(100vw - 2rem); overflow: auto; }}
</style>
